class ResidentListView(View):
    """
    View to list all residents.
    """
    def get(self, request):
        residents = Resident.objects.all()
        serializer = ResidentSerializer(residents, many=True)
        return render(request, 'residents/resident_list.html', {'residents': serializer.data})

class ResidentDetailView(View):
    """
    View to display a single resident's details.
    """
