    """Check if a token is a subquery."""
    return isinstance(token, (Parenthesis, IdentifierList)) and len(token.tokens) > 1

def is_subquery_root(token):
    """Check if a token is a subquery root."""
    return isinstance(token, (Function, IdentifierList)) and any(is_subquery(t) for t in token.tokens)

